&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# @title Show final memory and time stats&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;used_memory = &lt;span class=&#34;built_in&#34;&gt;round&lt;/span&gt;(torch.cuda.max_memory_reserved() / &lt;span class=&#34;number&#34;&gt;1024&lt;/span&gt; / &lt;span class=&#34;number&#34;&gt;1024&lt;/span&gt; / &lt;span class=&#34;number&#34;&gt;1024&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;used_memory_for_lora = &lt;span class=&#34;built_in&#34;&gt;round&lt;/span&gt;(used_memory - start_gpu_memory, &lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;used_percentage = &lt;span class=&#34;built_in&#34;&gt;round&lt;/span&gt;(used_memory / max_memory * &lt;span class=&#34;number&#34;&gt;100&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;lora_percentage = &lt;span class=&#34;built_in&#34;&gt;round&lt;/span&gt;(used_memory_for_lora / max_memory * &lt;span class=&#34;number&#34;&gt;100&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;f&amp;quot;&lt;span class=&#34;subst&#34;&gt;&amp;#123;trainer_stats.metrics[&lt;span class=&#34;string&#34;&gt;&amp;#x27;train_runtime&amp;#x27;&lt;/span&gt;]&amp;#125;&lt;/span&gt; seconds used for training.&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;string&#34;&gt;f&amp;quot;&lt;span class=&#34;subst&#34;&gt;&amp;#123;&lt;span class=&#34;built_in&#34;&gt;round&lt;/span&gt;(trainer_stats.metrics[&lt;span class=&#34;string&#34;&gt;&amp;#x27;train_runtime&amp;#x27;&lt;/span&gt;]/&lt;span class=&#34;number&#34;&gt;60&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;)&amp;#125;&lt;/span&gt; minutes used for training.&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;f&amp;quot;Peak reserved memory = &lt;span class=&#34;subst&#34;&gt;&amp;#123;used_memory&amp;#125;&lt;/span&gt; GB.&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;f&amp;quot;Peak reserved memory for training = &lt;span class=&#34;subst&#34;&gt;&amp;#123;used_memory_for_lora&amp;#125;&lt;/span&gt; GB.&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;f&amp;quot;Peak reserved memory % of max memory = &lt;span class=&#34;subst&#34;&gt;&amp;#123;used_percentage&amp;#125;&lt;/span&gt; %.&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;f&amp;quot;Peak reserved memory for training % of max memory = &lt;span class=&#34;subst&#34;&gt;&amp;#123;lora_percentage&amp;#125;&lt;/span&gt; %.&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;pre&gt;&lt;code&gt;412.4279 seconds used for training.
6.87 minutes used for training.
Peak reserved memory = 9.922 GB.
Peak reserved memory for training = 0.242 GB.
Peak reserved memory % of max memory = 68.132 %.
Peak reserved memory for training % of max memory = 1.662 %.
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;a name=&#34;Inference&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;Inference&#34;&gt;Inference&lt;/h3&gt;
&lt;p&gt;Let’s run the model! You can change the instruction and input - leave the output blank!&lt;/p&gt;
&lt;p&gt;We use &lt;code&gt;min_p = 0.1&lt;/code&gt; and &lt;code&gt;temperature = 1.5&lt;/code&gt;. Read this &lt;a href=&#34;https://x.com/menhguin/status/1826132708508213629&#34;&gt;Tweet&lt;/a&gt; for more information on why.&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;FastVisionModel.for_inference(model) &lt;span class=&#34;comment&#34;&gt;# Enable for inference!&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;image = dataset[&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;][&lt;span class=&#34;string&#34;&gt;&amp;quot;image&amp;quot;&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;instruction = &lt;span class=&#34;string&#34;&gt;&amp;quot;Write the LaTeX representation for this image.&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;messages = [&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;span class=&#34;string&#34;&gt;&amp;quot;role&amp;quot;&lt;/span&gt;: &lt;span class=&#34;string&#34;&gt;&amp;quot;user&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;content&amp;quot;&lt;/span&gt;: [&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#123;&lt;span class=&#34;string&#34;&gt;&amp;quot;type&amp;quot;&lt;/span&gt;: &lt;span class=&#34;string&#34;&gt;&amp;quot;image&amp;quot;&lt;/span&gt;&amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#123;&lt;span class=&#34;string&#34;&gt;&amp;quot;type&amp;quot;&lt;/span&gt;: &lt;span class=&#34;string&#34;&gt;&amp;quot;text&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;text&amp;quot;&lt;/span&gt;: instruction&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    ]&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;input_text = tokenizer.apply_chat_template(messages, add_generation_prompt = &lt;span class=&#34;literal&#34;&gt;True&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;inputs = tokenizer(&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    image,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    input_text,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    add_special_tokens = &lt;span class=&#34;literal&#34;&gt;False&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    return_tensors = &lt;span class=&#34;string&#34;&gt;&amp;quot;pt&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;).to(&lt;span class=&#34;string&#34;&gt;&amp;quot;cuda&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;from&lt;/span&gt; transformers &lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; TextStreamer&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;text_streamer = TextStreamer(tokenizer, skip_prompt = &lt;span class=&#34;literal&#34;&gt;True&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;_ = model.generate(**inputs, streamer = text_streamer, max_new_tokens = &lt;span class=&#34;number&#34;&gt;128&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                   use_cache = &lt;span class=&#34;literal&#34;&gt;True&lt;/span&gt;, temperature = &lt;span class=&#34;number&#34;&gt;1.5&lt;/span&gt;, min_p = &lt;span class=&#34;number&#34;&gt;0.1&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;pre&gt;&lt;code&gt;H ^ &amp;#123; \prime &amp;#125; = \beta N \int d \lambda \biggl \&amp;#123; \frac &amp;#123; 1 &amp;#125; &amp;#123; 2 \beta ^ &amp;#123; 2 &amp;#125; N ^ &amp;#123; 2 &amp;#125; &amp;#125; \partial _ &amp;#123; \lambda &amp;#125; \zeta ^ &amp;#123; \dagger &amp;#125; \partial _ &amp;#123; \lambda &amp;#125; \zeta + V ( \lambda ) \zeta ^ &amp;#123; \dagger &amp;#125; \zeta \biggr \&amp;#125; \ .&amp;lt;|im_end|&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;a name=&#34;Save&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;Saving-loading-finetuned-models&#34;&gt;Saving, loading finetuned models&lt;/h3&gt;
&lt;p&gt;To save the final model as LoRA adapters, either use Hugging Face’s &lt;code&gt;push_to_hub&lt;/code&gt; for an online save or &lt;code&gt;save_pretrained&lt;/code&gt; for a local save.&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;[NOTE]&lt;/strong&gt; This ONLY saves the LoRA adapters, and not the full model. To save to 16bit or GGUF, scroll down!&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;YOUR_HF_TOKEN = &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;model.save_pretrained(&lt;span class=&#34;string&#34;&gt;&amp;quot;qwen3.5_4B_lora_latex&amp;quot;&lt;/span&gt;)  &lt;span class=&#34;comment&#34;&gt;# Local saving&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;tokenizer.save_pretrained(&lt;span class=&#34;string&#34;&gt;&amp;quot;qwen3.5_4B_lora_latex&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;model.push_to_hub(&lt;span class=&#34;string&#34;&gt;&amp;quot;Weidows/qwen3.5_4B_lora_latex&amp;quot;&lt;/span&gt;, token = YOUR_HF_TOKEN) &lt;span class=&#34;comment&#34;&gt;# Online saving&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;tokenizer.push_to_hub(&lt;span class=&#34;string&#34;&gt;&amp;quot;Weidows/qwen3.5_4B_lora_latex&amp;quot;&lt;/span&gt;, token = YOUR_HF_TOKEN) &lt;span class=&#34;comment&#34;&gt;# Online saving&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;pre&gt;&lt;code&gt;README.md:   0%|          | 0.00/529 [00:00&amp;lt;?, ?B/s]



Processing Files (0 / 0)      : |          |  0.00B /  0.00B



New Data Upload               : |          |  0.00B /  0.00B



  ...adapter_model.safetensors:   0%|          | 52.7kB /  155MB


Saved model to https://huggingface.co/Weidows/qwen3.5_4B_lora_latex



Processing Files (0 / 0)      : |          |  0.00B /  0.00B



New Data Upload               : |          |  0.00B /  0.00B



  ...mpof4d0ctj/tokenizer.json:  60%|#####9    | 12.0MB / 20.0MB
&lt;/code&gt;&lt;/pre&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; torch&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; gc&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 1. 显式删除模型和推理/训练器&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;try&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;del&lt;/span&gt; model&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;del&lt;/span&gt; tokenizer&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;del&lt;/span&gt; trainer &lt;span class=&#34;comment&#34;&gt;# 如果你定义了训练器，必须删掉它&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;except&lt;/span&gt; NameError:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;pass&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 2. 强制垃圾回收&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;gc.collect()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 3. 清空 CUDA 缓存&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;torch.cuda.empty_cache()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 4. 特别针对 Unsloth：重置峰值监控（有时能触发系统级回收）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;torch.cuda.reset_peak_memory_stats()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# torch.cuda.reset_accumulated_stats() # Removed this line as it caused an AttributeError&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;f&amp;quot;清理后逻辑占用: &lt;span class=&#34;subst&#34;&gt;&amp;#123;torch.cuda.memory_allocated() / &lt;span class=&#34;number&#34;&gt;1024&lt;/span&gt;**&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;.2&lt;/span&gt;f&amp;#125;&lt;/span&gt; MB&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;pre&gt;&lt;code&gt;清理后逻辑占用: 0.00 MB
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;现在，我们将从本地保存的路径加载微调后的模型和 tokenizer。&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;from&lt;/span&gt; unsloth &lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; FastVisionModel&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 从本地路径加载微调后的模型&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;model, tokenizer = FastVisionModel.from_pretrained(&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    model_name = &lt;span class=&#34;string&#34;&gt;&amp;quot;qwen3.5_4B_lora_latex&amp;quot;&lt;/span&gt;, &lt;span class=&#34;comment&#34;&gt;# 本地保存的模型路径&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    load_in_4bit = &lt;span class=&#34;literal&#34;&gt;True&lt;/span&gt;, &lt;span class=&#34;comment&#34;&gt;# 根据需要选择加载方式，这里使用4bit加载&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 设置模型为推理模式&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;FastVisionModel.for_inference(model)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;微调模型已成功加载并设置为推理模式。&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
